interceptor.preaction:

Util dt = new Util();
String date=dt.getDate();
String measureDt = rrequest.getStringAttribute("MEASURE_DT", "");
measureDt=measureDt==null?"":measureDt;


String mdt = (String) rrequest.getRequest().getSession().getAttribute("MDT");
mdt=mdt==null?"":mdt;

if(measureDt.equals("")){
	if(!mdt.equals("")){
		rrequest.setAttribute("MEASURE_DT", mdt);
		rrequest.getRequest().getSession().setAttribute("MDT", "");
	}else{
		rrequest.setAttribute("MEASURE_DT", date);

	}
}

